mapper.select:
select 
from litemall_ai_review_risk_task
where analysis_id = #{analysisId,jdbcType=INTEGER}
  and risk_type = #{riskType,jdbcType=VARCHAR}
  and deleted = 0
limit 1

select 
from litemall_ai_review_risk_task

  deleted = 0
  and risk_level = #{riskLevel,jdbcType=VARCHAR}
  and risk_type = #{riskType,jdbcType=VARCHAR}
  and status = #{status,jdbcType=VARCHAR}

order by created_time desc
